void mm_init() {
    pagemeta_start = (struct page *) PGROUNDUP((uint64) end);
    for (int i = 0; i < NCPU; i++) {
        init_buddy(&mem_pools[i], 
                   (struct page *) PGROUNDUP((uint64) end) + i * PAGES_PER_CPU,
                   (uint64) START_MEM + i * PAGES_PER_CPU * PGSIZE, 
                   PAGES_PER_CPU);
    }
}
